SELECT index_name, current_value
FROM market_indexes
WHERE current_value = (SELECT MAX(current_value) FROM market_indexes);

SELECT MAX(year_high) AS max_year_high, MIN(year_low) AS min_year_low
FROM market_indexes
WHERE index_name = 'NASDAQ';

SELECT AVG(recommendation_score) AS average_recommendation_score
FROM stock_recommenders
WHERE user_id = 1;

SELECT DISTINCT stock_id
FROM user_watchlist
WHERE watchlist_name = 'Tech Stocks';
